import{_ as t}from"./_plugin-vue_export-helper.cdc0426e.js";import{o as p,c as o,a as s,b as n,d as e,e as c,r as i}from"./app.416cc04c.js";const l={},u=s("h2",{id:"前言",tabindex:"-1"},[s("a",{class:"header-anchor",href:"#前言","aria-hidden":"true"},"#"),n(" 前言")],-1),r={href:"https://github.com/axios/axios",target:"_blank",rel:"noopener noreferrer"},d={href:"https://axios-http.com/docs/intro",target:"_blank",rel:"noopener noreferrer"},k=c(`<h2 id="追溯-axios-初始化" tabindex="-1"><a class="header-anchor" href="#追溯-axios-初始化" aria-hidden="true">#</a> 追溯 axios 初始化</h2><p>我们在项目中使用 <code>axios</code> 时，一般都是安装导入然后对其进行二次封装，这说明它默认导出了一个 <code>axios</code> 对象。打开 <code>axios</code> 源码的 <code>package.json</code> 文件查看 <code>main</code> 字段，可以知道它的入口文件是同路径下的 <code>index.js</code>，里面的内容不多，粗略如下：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// index.js</span>
<span class="token keyword">import</span> axios <span class="token keyword">from</span> <span class="token string">&#39;./lib/axios.js&#39;</span><span class="token punctuation">;</span>

<span class="token keyword">const</span> <span class="token punctuation">{</span> <span class="token comment">/* omission */</span> <span class="token punctuation">}</span> <span class="token operator">=</span> axios<span class="token punctuation">;</span>

<span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token punctuation">{</span>
  axios <span class="token keyword">as</span> <span class="token keyword">default</span><span class="token punctuation">,</span>
  <span class="token comment">/* omission */</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>它默认导出了一个 <code>axios</code> 对象，这个对象来自 <code>lib/axios.js</code>，里面的代码省略如下：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// lib/axios.js</span>
<span class="token keyword">import</span> defaults <span class="token keyword">from</span> <span class="token string">&#39;./defaults/index.js&#39;</span><span class="token punctuation">;</span>

<span class="token keyword">function</span> <span class="token function">createInstance</span><span class="token punctuation">(</span><span class="token parameter">defaultConfig</span><span class="token punctuation">)</span> <span class="token punctuation">{</span> <span class="token comment">/* do something */</span> <span class="token punctuation">}</span>

<span class="token keyword">const</span> axios <span class="token operator">=</span> <span class="token function">createInstance</span><span class="token punctuation">(</span>defaults<span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token keyword">export</span> <span class="token keyword">default</span> axios<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>可以看到我们使用的 <code>axios</code> 是由 <code>createInstance</code> 函数返回的，那么它在内部做了什么呢？</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// lib/axios.js</span>
<span class="token keyword">import</span> utils <span class="token keyword">from</span> <span class="token string">&#39;./utils.js&#39;</span><span class="token punctuation">;</span>
<span class="token keyword">import</span> bind <span class="token keyword">from</span> <span class="token string">&#39;./helpers/bind.js&#39;</span><span class="token punctuation">;</span>
<span class="token keyword">import</span> Axios <span class="token keyword">from</span> <span class="token string">&#39;./core/Axios.js&#39;</span><span class="token punctuation">;</span>
<span class="token keyword">import</span> mergeConfig <span class="token keyword">from</span> <span class="token string">&#39;./core/mergeConfig.js&#39;</span><span class="token punctuation">;</span>

<span class="token keyword">function</span> <span class="token function">createInstance</span><span class="token punctuation">(</span><span class="token parameter">defaultConfig</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">const</span> context <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Axios</span><span class="token punctuation">(</span>defaultConfig<span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token keyword">const</span> instance <span class="token operator">=</span> <span class="token function">bind</span><span class="token punctuation">(</span><span class="token class-name">Axios</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span>request<span class="token punctuation">,</span> context<span class="token punctuation">)</span><span class="token punctuation">;</span>

  <span class="token comment">// Copy axios.prototype to instance</span>
  utils<span class="token punctuation">.</span><span class="token function">extend</span><span class="token punctuation">(</span>instance<span class="token punctuation">,</span> <span class="token class-name">Axios</span><span class="token punctuation">.</span>prototype<span class="token punctuation">,</span> context<span class="token punctuation">,</span> <span class="token punctuation">{</span><span class="token literal-property property">allOwnKeys</span><span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

  <span class="token comment">// Copy context to instance</span>
  utils<span class="token punctuation">.</span><span class="token function">extend</span><span class="token punctuation">(</span>instance<span class="token punctuation">,</span> context<span class="token punctuation">,</span> <span class="token keyword">null</span><span class="token punctuation">,</span> <span class="token punctuation">{</span><span class="token literal-property property">allOwnKeys</span><span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

  <span class="token comment">// Factory for creating new instances</span>
  instance<span class="token punctuation">.</span><span class="token function-variable function">create</span> <span class="token operator">=</span> <span class="token keyword">function</span> <span class="token function">create</span><span class="token punctuation">(</span><span class="token parameter">instanceConfig</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> <span class="token function">createInstance</span><span class="token punctuation">(</span><span class="token function">mergeConfig</span><span class="token punctuation">(</span>defaultConfig<span class="token punctuation">,</span> instanceConfig<span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span><span class="token punctuation">;</span>

  <span class="token keyword">return</span> instance<span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>可以看到在这个函数内部主要做了 5 件事，分别是：</p><ol><li>构造一个 <code>Axios</code> 实例</li><li>调用自封装的 <code>bind</code> 函数，传入 <code>Axios</code> 原型的 <code>request</code> 方法和 <code>Axios</code> 实例，返回一个新的函数</li><li>拷贝 <code>Axios</code> 原型的自有数据至这个新函数，并将其中函数的 <code>this</code> 指向 <code>Axios</code> 实例</li><li>拷贝 <code>Axios</code> 实例的自有数据至这个新函数</li><li>给这个新函数添加一个 <code>create</code> 方法，也就是我们常用的创建 <code>axios</code> 副本方法</li></ol><p>最后返回这个函数，也就是我们使用的 <code>axios</code>；它并不是 <code>Axios</code> 实例，但存在 <code>Axios</code> 原型和 <code>Axios</code> 实例的所有数据。</p><h2 id="构造-axios-实例" tabindex="-1"><a class="header-anchor" href="#构造-axios-实例" aria-hidden="true">#</a> 构造 Axios 实例</h2><p>第一步是构造 <code>Axios</code> 的实例， <code>Axios</code> 定义在 <code>lib/core/Axios.js</code> 中，它的简略代码如下：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// lib/core/Axios.js</span>
<span class="token keyword">class</span> <span class="token class-name">Axios</span> <span class="token punctuation">{</span>
  <span class="token function">constructor</span><span class="token punctuation">(</span><span class="token parameter">instanceConfig</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">this</span><span class="token punctuation">.</span>defaults <span class="token operator">=</span> instanceConfig<span class="token punctuation">;</span>
    <span class="token keyword">this</span><span class="token punctuation">.</span>interceptors <span class="token operator">=</span> <span class="token punctuation">{</span>
      <span class="token literal-property property">request</span><span class="token operator">:</span> <span class="token keyword">new</span> <span class="token class-name">InterceptorManager</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
      <span class="token literal-property property">response</span><span class="token operator">:</span> <span class="token keyword">new</span> <span class="token class-name">InterceptorManager</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
    <span class="token punctuation">}</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span>

  <span class="token function">request</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span> <span class="token comment">/* omission */</span> <span class="token punctuation">}</span>

  <span class="token function">getUri</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span> <span class="token comment">/* omission */</span> <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="配置项" tabindex="-1"><a class="header-anchor" href="#配置项" aria-hidden="true">#</a> 配置项</h3><p>这里我们忽略 <code>Axios</code> 原型的 <code>request</code> 和 <code>getUri</code> 方法；可以看到在 <code>constructor</code> 方法内将传入的数据赋值给了 <code>defaults</code> 属性，这里的数据来自 <code>lib/defaults/index.js</code>；其中是默认的一些配置，比如常用的 <code>baseURL</code>、<code>timeout</code> 等；我们可以通过 <code>defaults</code> 属性修改这些配置，比如：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>axios<span class="token punctuation">.</span>defaults<span class="token punctuation">.</span>baseURL <span class="token operator">=</span> <span class="token string">&#39;https://yuanyxh.com/&#39;</span><span class="token punctuation">;</span>

<span class="token comment">// or</span>
<span class="token keyword">const</span> request <span class="token operator">=</span> axios<span class="token punctuation">.</span><span class="token function">create</span><span class="token punctuation">(</span><span class="token punctuation">{</span>
  <span class="token literal-property property">baseURL</span><span class="token operator">:</span> <span class="token string">&#39;https://yuanyxh.com/&#39;</span><span class="token punctuation">,</span>
  <span class="token literal-property property">timeout</span><span class="token operator">:</span> <span class="token number">60000</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="拦截器" tabindex="-1"><a class="header-anchor" href="#拦截器" aria-hidden="true">#</a> 拦截器</h3><p>添加 <code>defaults</code> 属性的下一行又添加了 <code>interceptors</code> 属性，它被赋值为一个包含 <code>request</code> 和 <code>response</code> 属性的对象，这两个属性的值是 <code>InterceptorManager</code> 的实例，<code>InterceptorManager</code> 定义在 <code>lib/core/InterceptorManager.js</code>，代码粗略如下：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">class</span> <span class="token class-name">InterceptorManager</span> <span class="token punctuation">{</span>
  <span class="token function">constructor</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">this</span><span class="token punctuation">.</span>handlers <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span>

  <span class="token function">use</span><span class="token punctuation">(</span><span class="token parameter">fulfilled<span class="token punctuation">,</span> rejected<span class="token punctuation">,</span> options</span><span class="token punctuation">)</span> <span class="token punctuation">{</span> <span class="token comment">/* omission */</span> <span class="token punctuation">}</span>

  <span class="token function">eject</span><span class="token punctuation">(</span><span class="token parameter">id</span><span class="token punctuation">)</span> <span class="token punctuation">{</span> <span class="token comment">/* omission */</span> <span class="token punctuation">}</span>

  <span class="token function">clear</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span> <span class="token comment">/* omission */</span> <span class="token punctuation">}</span>

  <span class="token function">forEach</span><span class="token punctuation">(</span><span class="token parameter">fn</span><span class="token punctuation">)</span> <span class="token punctuation">{</span> <span class="token comment">/* omission */</span> <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>有没有觉得很熟悉？这其实就是我们常用的请求、响应拦截器；<code>InterceptorManager</code> 原型方法的作用分别如下：</p><ul><li><code>use</code>: 注册一个请求或响应拦截器，将 <code>fulfilled</code>、 <code>rejected</code>, <code>options</code> 合并为一个对象并添加至 <code>handlers</code> 数组，返回索引。</li><li><code>eject</code>: 从 <code>handlers</code> 数组中清除指定索引的请求或响应拦截器</li><li><code>clear</code>: 重置 <code>handlers</code> 数组</li><li><code>forEach</code>: 遍历数组并将数组项传入 <code>fn</code> 回调中</li></ul><p>所以我们才能通过 <code>axios.interceptors.(request | response).use</code> 注册拦截器并处理请求或响应数据。</p><h3 id="请求别名" tabindex="-1"><a class="header-anchor" href="#请求别名" aria-hidden="true">#</a> 请求别名</h3><p>在 <code>Axios</code> 类外部，还给 <code>Axios</code> 原型添加了我们常用的 <code>get</code>、<code>post</code> 等方法：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// lib/core/Axios.js</span>
utils<span class="token punctuation">.</span><span class="token function">forEach</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token string">&#39;delete&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;get&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;head&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;options&#39;</span><span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token keyword">function</span> <span class="token function">forEachMethodNoData</span><span class="token punctuation">(</span><span class="token parameter">method</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token class-name">Axios</span><span class="token punctuation">.</span>prototype<span class="token punctuation">[</span>method<span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token keyword">function</span><span class="token punctuation">(</span><span class="token parameter">url<span class="token punctuation">,</span> config</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> <span class="token keyword">this</span><span class="token punctuation">.</span><span class="token function">request</span><span class="token punctuation">(</span><span class="token function">mergeConfig</span><span class="token punctuation">(</span>config <span class="token operator">||</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token punctuation">{</span>
      method<span class="token punctuation">,</span>
      url<span class="token punctuation">,</span>
      <span class="token literal-property property">data</span><span class="token operator">:</span> <span class="token punctuation">(</span>config <span class="token operator">||</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">.</span>data
    <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

utils<span class="token punctuation">.</span><span class="token function">forEach</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token string">&#39;post&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;put&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;patch&#39;</span><span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token keyword">function</span> <span class="token function">forEachMethodWithData</span><span class="token punctuation">(</span><span class="token parameter">method</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>

  <span class="token keyword">function</span> <span class="token function">generateHTTPMethod</span><span class="token punctuation">(</span><span class="token parameter">isForm</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> <span class="token keyword">function</span> <span class="token function">httpMethod</span><span class="token punctuation">(</span><span class="token parameter">url<span class="token punctuation">,</span> data<span class="token punctuation">,</span> config</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
      <span class="token keyword">return</span> <span class="token keyword">this</span><span class="token punctuation">.</span><span class="token function">request</span><span class="token punctuation">(</span><span class="token function">mergeConfig</span><span class="token punctuation">(</span>config <span class="token operator">||</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token punctuation">{</span>
        method<span class="token punctuation">,</span>
        <span class="token literal-property property">headers</span><span class="token operator">:</span> isForm <span class="token operator">?</span> <span class="token punctuation">{</span>
          <span class="token string-property property">&#39;Content-Type&#39;</span><span class="token operator">:</span> <span class="token string">&#39;multipart/form-data&#39;</span>
        <span class="token punctuation">}</span> <span class="token operator">:</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">,</span>
        url<span class="token punctuation">,</span>
        data
      <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span>

  <span class="token class-name">Axios</span><span class="token punctuation">.</span>prototype<span class="token punctuation">[</span>method<span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token function">generateHTTPMethod</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

  <span class="token class-name">Axios</span><span class="token punctuation">.</span>prototype<span class="token punctuation">[</span>method <span class="token operator">+</span> <span class="token string">&#39;Form&#39;</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token function">generateHTTPMethod</span><span class="token punctuation">(</span><span class="token boolean">true</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>可以看到我们常用的 <code>get</code>、<code>post</code> 等方法最终都是调用了 <code>request</code> 方法，它们只是一个过渡或者说别名。</p><h2 id="绑定上下文" tabindex="-1"><a class="header-anchor" href="#绑定上下文" aria-hidden="true">#</a> 绑定上下文</h2><p>构造出 <code>Axios</code> 实例后调用了自实现的 <code>bind</code> 函数并传入了 <code>Axios</code> 原型的 <code>request</code> 方法和 <code>Axios</code> 实例；<code>bind</code> 代码如下：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// lib/helpers/bind.js</span>
<span class="token keyword">function</span> <span class="token function">bind</span><span class="token punctuation">(</span><span class="token parameter">fn<span class="token punctuation">,</span> thisArg</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">return</span> <span class="token keyword">function</span> <span class="token function">wrap</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> <span class="token function">fn</span><span class="token punctuation">.</span><span class="token function">apply</span><span class="token punctuation">(</span>thisArg<span class="token punctuation">,</span> arguments<span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>bind</code> 函数返回了一个新函数 <code>instance</code>，执行它时会调用 <code>fn</code> 并将它内部的 <code>this</code> 指向 <code>thisArg</code>。从代码上下文看，这里的 <code>fn</code> 是 <code>request</code> 方法，<code>thisArg</code> 是 <code>Axios</code> 实例。</p><h2 id="拷贝数据" tabindex="-1"><a class="header-anchor" href="#拷贝数据" aria-hidden="true">#</a> 拷贝数据</h2><p>接下来又将 <code>Axios</code> 原型与实例的数据全部拷贝至 <code>instance</code> 身上，代码使用了 <code>utils.extend</code> 方法，实现如下：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// lib/utils.js</span>
<span class="token keyword">const</span> <span class="token function-variable function">extend</span> <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token parameter">a<span class="token punctuation">,</span> b<span class="token punctuation">,</span> thisArg<span class="token punctuation">,</span> <span class="token punctuation">{</span>allOwnKeys<span class="token punctuation">}</span><span class="token operator">=</span> <span class="token punctuation">{</span><span class="token punctuation">}</span></span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
  <span class="token function">forEach</span><span class="token punctuation">(</span>b<span class="token punctuation">,</span> <span class="token punctuation">(</span><span class="token parameter">val<span class="token punctuation">,</span> key</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
    <span class="token keyword">if</span> <span class="token punctuation">(</span>thisArg <span class="token operator">&amp;&amp;</span> <span class="token function">isFunction</span><span class="token punctuation">(</span>val<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
      a<span class="token punctuation">[</span>key<span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token function">bind</span><span class="token punctuation">(</span>val<span class="token punctuation">,</span> thisArg<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
      a<span class="token punctuation">[</span>key<span class="token punctuation">]</span> <span class="token operator">=</span> val<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token punctuation">{</span>allOwnKeys<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token keyword">return</span> a<span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>主要是遍历 <code>b</code> 并将其中数据全部赋值给 <code>a</code>，如果 <code>thisArg</code> 存在且遍历到的值是函数则调用 <code>bind</code> 函数改变原方法的 <code>this</code> 指向。</p><h2 id="添加-create-方法" tabindex="-1"><a class="header-anchor" href="#添加-create-方法" aria-hidden="true">#</a> 添加 create 方法</h2><p>拷贝完数据后，代码给 <code>instance</code> 函数添加了一个 <code>create</code> 方法，内部调用了 <code>createInstance</code> 并将配置合并后传给了它，以此来创建 <code>axios</code> 副本。</p><p>最后将 <code>instance</code> 返回就得到了我们所使用的 <code>axios</code>，随后还添加了一些工具，比如用于取消请求的 <code>CancelToken</code> 构造器，用于并发请求的 <code>all</code> 方法，完整列表如下：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// Axios 类</span>
axios<span class="token punctuation">.</span>Axios <span class="token operator">=</span> Axios<span class="token punctuation">;</span>
<span class="token comment">// 取消请求的自定义 Error 对象, 继承自 AxiosError</span>
axios<span class="token punctuation">.</span>CanceledError <span class="token operator">=</span> CanceledError<span class="token punctuation">;</span>
<span class="token comment">// CancelToken 构造器, 用于取消请求</span>
axios<span class="token punctuation">.</span>CancelToken <span class="token operator">=</span> CancelToken<span class="token punctuation">;</span>
<span class="token comment">// 工具函数, 判断对应的请求是否已取消</span>
axios<span class="token punctuation">.</span>isCancel <span class="token operator">=</span> isCancel<span class="token punctuation">;</span>
<span class="token comment">// axios 版本</span>
axios<span class="token punctuation">.</span><span class="token constant">VERSION</span> <span class="token operator">=</span> <span class="token constant">VERSION</span><span class="token punctuation">;</span>
<span class="token comment">// 将对象转换为 FormData 的工具函数</span>
axios<span class="token punctuation">.</span>toFormData <span class="token operator">=</span> toFormData<span class="token punctuation">;</span>
<span class="token comment">// 自定义的 Error 对象，继承自 Error</span>
axios<span class="token punctuation">.</span>AxiosError <span class="token operator">=</span> AxiosError<span class="token punctuation">;</span>
<span class="token comment">// CanceledError 的别名</span>
axios<span class="token punctuation">.</span>Cancel <span class="token operator">=</span> axios<span class="token punctuation">.</span>CanceledError<span class="token punctuation">;</span>
<span class="token comment">// 并发请求</span>
axios<span class="token punctuation">.</span><span class="token function-variable function">all</span> <span class="token operator">=</span> <span class="token keyword">function</span> <span class="token function">all</span><span class="token punctuation">(</span><span class="token parameter">promises</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">return</span> Promise<span class="token punctuation">.</span><span class="token function">all</span><span class="token punctuation">(</span>promises<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>
<span class="token comment">// apply 的语法糖</span>
axios<span class="token punctuation">.</span>spread <span class="token operator">=</span> spread<span class="token punctuation">;</span>
<span class="token comment">// 判断错误对象是否是 AxiosError</span>
axios<span class="token punctuation">.</span>isAxiosError <span class="token operator">=</span> isAxiosError<span class="token punctuation">;</span>
<span class="token comment">// 合并配置的工具函数</span>
axios<span class="token punctuation">.</span>mergeConfig <span class="token operator">=</span> mergeConfig<span class="token punctuation">;</span>
<span class="token comment">// headers 相关的工具类</span>
axios<span class="token punctuation">.</span>AxiosHeaders <span class="token operator">=</span> AxiosHeaders<span class="token punctuation">;</span>
<span class="token comment">// FormData 转换为 json 的工具函数</span>
axios<span class="token punctuation">.</span><span class="token function-variable function">formToJSON</span> <span class="token operator">=</span> <span class="token parameter">thing</span> <span class="token operator">=&gt;</span> <span class="token function">formDataToJSON</span><span class="token punctuation">(</span>utils<span class="token punctuation">.</span><span class="token function">isHTMLForm</span><span class="token punctuation">(</span>thing<span class="token punctuation">)</span> <span class="token operator">?</span> <span class="token keyword">new</span> <span class="token class-name">FormData</span><span class="token punctuation">(</span>thing<span class="token punctuation">)</span> <span class="token operator">:</span> thing<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token comment">// http 状态码对象</span>
axios<span class="token punctuation">.</span>HttpStatusCode <span class="token operator">=</span> HttpStatusCode<span class="token punctuation">;</span>
<span class="token comment">// default 指向自己</span>
axios<span class="token punctuation">.</span>default <span class="token operator">=</span> axios<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>-- end</p>`,39);function v(m,b){const a=i("ExternalLinkIcon");return p(),o("div",null,[u,s("p",null,[s("a",r,[n("axios"),e(a)]),n(" 版本 1.3.4，建议阅读 "),s("a",d,[n("axios 文档"),e(a)]),n("，熟悉相关 Api 后进行学习。")]),k])}const h=t(l,[["render",v],["__file","axios_源码学习(一).html.vue"]]);export{h as default};
